import React, { useEffect, useState } from 'react'
import { useLocation, Link, Navigate, useNavigate } from 'react-router-dom'

import '../css/login.css'

export default function Registration() {
    const [showPass, setshowPass] = useState(false)
    const [number, setNumber] = useState('')
    const [password, setPassword] = useState('')
    const [loginAllow, setloginAllow] = useState(false)
    const navigate = useNavigate()

    useEffect(() => {
        if (number != '' && password != '') {
            setloginAllow(true)
        } else {
            setloginAllow(false)
        }



    }, [number, password])

    const handleChange = () => {
        setshowPass(!showPass)
    }

    const authentication = () => {
        navigate('/')
    }

    return (
        <div className='main-body'>
            <section className='reg-body'>

                <div className='login-third-part-third-div'>
                    <form action="">
                        <h2 style={{color:'gray'}}>Registration</h2>
                        <br />
                        <div className='login-third-part-input'>
                            <div className='firstname-surname'>
                            <input id='part-input' type="text" value={number} onChange={(e) => setNumber(e.target.value)} placeholder='Enter First Name' />
                            <input id='part-input' type="text" value={number} onChange={(e) => setNumber(e.target.value)} placeholder='Enter Surname' />

                            </div>
                            
                            <input id='part-input' type="text" value={number} onChange={(e) => setNumber(e.target.value)} placeholder='Enter Phone ' />
                            <input id='part-input' type="text" value={number} onChange={(e) => setNumber(e.target.value)} placeholder='Enter Email' />
                            <input id='part-input' type="text" value={number} onChange={(e) => setNumber(e.target.value)} placeholder='Enter Adderss'  />
                            <input id='part-input' type="text" value={number} onChange={(e) => setNumber(e.target.value)} placeholder='Enter NID/ Birth Certificate' />
                            <div className='password-box'>
                                <input id='part-input' value={password} onChange={(e) => setPassword(e.target.value)} type={`${showPass ? 'text' : 'password'}`} placeholder='Enter Password' />
                                <i onClick={handleChange} class="eye fa-regular fa-eye"></i>
                            </div>
                            <div className='password-box'>
                                <input id='part-input' value={password} onChange={(e) => setPassword(e.target.value)} type={`${showPass ? 'text' : 'password'}`} placeholder='Re-writePassword' />
                                <i onClick={handleChange} class="eye fa-regular fa-eye"></i>
                            </div>
                            <button className={`login-btn ${loginAllow ? 'active-login-btn' : ''}`} onClick={authentication} id='part-input'>Login</button>
                        </div>
                        <p>Already Have Account?</p>
                        <Link to={'/registration'}><h3>Login?</h3></Link>
                    </form>
                </div>

            </section>

        </div>
    )
}
